const jwt = require('jsonwebtoken');
const dotenv = require('dotenv');

dotenv.config();

const authMiddleware = (req, res, next) => {
    // Get token from header
    const token = req.header('Authorization')?.replace('Bearer ', '');

    // Check if not token
    if (!token) {
        return res.status(401).json({ message: 'No token, authorization denied' });
    }

    try {
        // Verify token
        const decoded = jwt.verify(token, process.env.JWT_SECRET);

        // Add user from payload
        req.user = decoded;
        next();
    } catch (err) {
        res.status(401).json({ message: 'Token is not valid' });
    }
};

module.exports = authMiddleware;

const express = require('express');
const router = express.Router();
const pool = require('../db');
const authMiddleware = require('../middleware/authMiddleware');

// Protect all admin routes
router.use(authMiddleware);

// Get all departments
router.get('/departments', async (req, res) => {
    try {
        const [rows] = await pool.execute('SELECT DISTINCT department FROM students UNION SELECT DISTINCT department FROM faculty UNION SELECT DISTINCT department FROM courses');
        res.json(rows.map(r => r.department).filter(d => d));
    } catch (error) {
        res.status(500).json({ message: 'Error fetching departments' });
    }
});

// Get all courses/subjects
router.get('/courses', async (req, res) => {
    try {
        const [rows] = await pool.execute('SELECT * FROM courses');
        res.json(rows);
    } catch (error) {
        res.status(500).json({ message: 'Error fetching courses' });
    }
});

// Add a new course
router.post('/courses', async (req, res) => {
    const { course_code, course_name, department, semester, credits } = req.body;
    try {
        await pool.execute(
            'INSERT INTO courses (course_code, course_name, department, semester, credits) VALUES (?, ?, ?, ?, ?)',
            [course_code, course_name, department, semester, credits]
        );
        res.status(201).json({ message: 'Course added successfully' });
    } catch (error) {
        res.status(500).json({ message: 'Error adding course' });
    }
});

// Update a course
router.put('/courses/:id', async (req, res) => {
    const { course_code, course_name, department, semester, credits } = req.body;
    try {
        await pool.execute(
            'UPDATE courses SET course_code = ?, course_name = ?, department = ?, semester = ?, credits = ? WHERE id = ?',
            [course_code, course_name, department, semester, credits, req.params.id]
        );
        res.json({ message: 'Course updated successfully' });
    } catch (error) {
        res.status(500).json({ message: 'Error updating course' });
    }
});

// Delete a course
router.delete('/courses/:id', async (req, res) => {
    try {
        await pool.execute('DELETE FROM courses WHERE id = ?', [req.params.id]);
        res.json({ message: 'Course deleted successfully' });
    } catch (error) {
        res.status(500).json({ message: 'Error deleting course' });
    }
});

// Get system stats
router.get('/system-stats', async (req, res) => {
    try {
        const [[{ user_count }]] = await pool.execute('SELECT COUNT(*) as user_count FROM users');
        const [[{ student_count }]] = await pool.execute('SELECT COUNT(*) as student_count FROM students');
        const [[{ faculty_count }]] = await pool.execute('SELECT COUNT(*) as faculty_count FROM faculty');
        const [[{ course_count }]] = await pool.execute('SELECT COUNT(*) as course_count FROM courses');

        res.json({
            totalUsers: user_count,
            totalStudents: student_count,
            totalFaculty: faculty_count,
            totalCourses: course_count,
            activeSessions: Math.floor(user_count * 0.8) // Mocked active session for now
        });
    } catch (error) {
        res.status(500).json({ message: 'Error fetching system stats' });
    }
});

module.exports = router;

const express = require('express');
const router = express.Router();
const pool = require('../db');
const authMiddleware = require('../middleware/authMiddleware');

// Protect all faculty routes
router.use(authMiddleware);

// Get faculty profile and assigned classes/courses
router.get('/:userId/profile', async (req, res) => {
    try {
        const [rows] = await pool.execute('SELECT * FROM faculty WHERE user_id = ?', [req.params.userId]);
        if (rows.length === 0) return res.status(404).json({ message: 'Faculty not found' });
        res.json(rows[0]);
    } catch (error) {
        res.status(500).json({ message: 'Error fetching faculty profile' });
    }
});

// Get class performance summary for a course
router.get('/class-performance/:courseId', async (req, res) => {
    try {
        const [[stats]] = await pool.execute(`
            SELECT 
                AVG(total_marks) as average_marks,
                MAX(total_marks) as highest_marks,
                MIN(total_marks) as lowest_marks,
                COUNT(student_id) as student_count
            FROM marks 
            WHERE course_id = ?
        `, [req.params.courseId]);

        const [atRisk] = await pool.execute(`
            SELECT COUNT(*) as risk_count FROM marks 
            WHERE course_id = ? AND total_marks < 60
        `, [req.params.courseId]);

        res.json({ ...stats, risk_count: atRisk[0].risk_count });
    } catch (error) {
        res.status(500).json({ message: 'Error fetching class performance' });
    }
});

// Upload / Update marks
router.post('/upload-marks', async (req, res) => {
    const { student_id, course_id, internal_marks, external_marks, semester, academic_year } = req.body;
    const total_marks = parseFloat(internal_marks) + parseFloat(external_marks);
    let grade = 'F';
    if (total_marks >= 90) grade = 'A+';
    else if (total_marks >= 80) grade = 'A';
    else if (total_marks >= 70) grade = 'B';
    else if (total_marks >= 60) grade = 'C';
    else if (total_marks >= 50) grade = 'D';

    try {
        await pool.execute(`
            INSERT INTO marks (student_id, course_id, internal_marks, external_marks, total_marks, grade, semester, academic_year) 
            VALUES (?, ?, ?, ?, ?, ?, ?, ?)
            ON DUPLICATE KEY UPDATE 
                internal_marks = VALUES(internal_marks),
                external_marks = VALUES(external_marks),
                total_marks = VALUES(total_marks),
                grade = VALUES(grade)
        `, [student_id, course_id, internal_marks, external_marks, total_marks, grade, semester, academic_year]);
        res.status(200).json({ message: 'Marks uploaded successfully' });
    } catch (error) {
        res.status(500).json({ message: 'Error uploading marks' });
    }
});

// Get students for a specific course (by department and semester)
router.get('/students-by-course/:courseId', async (req, res) => {
    try {
        const [[course]] = await pool.execute('SELECT department, semester FROM courses WHERE id = ?', [req.params.courseId]);
        if (!course) return res.status(404).json({ message: 'Course not found' });

        const [students] = await pool.execute('SELECT * FROM students WHERE department = ? AND semester = ?', [course.department, course.semester]);
        res.json(students);
    } catch (error) {
        res.status(500).json({ message: 'Error fetching students' });
    }
});

// Get analytics for faculty dashboard
router.get('/analytics', async (req, res) => {
    try {
        const [[stats]] = await pool.execute(`
             SELECT 
                (SELECT COUNT(*) FROM students) as total_students,
                (SELECT AVG(total_marks) FROM marks) as average_performance,
                (SELECT COUNT(*) FROM courses) as active_courses
        `);

        const [distribution] = await pool.execute(`
            SELECT department, COUNT(*) as count 
            FROM students 
            GROUP BY department
        `);

        res.json({
            stats: { ...stats, average_performance: parseFloat(stats.average_performance || 0).toFixed(2) },
            distribution
        });
    } catch (error) {
        res.status(500).json({ message: 'Error fetching analytics' });
    }
});

// Get grade distribution for a course
router.get('/grade-distribution/:courseId', async (req, res) => {
    try {
        const [rows] = await pool.execute(`
            SELECT grade as name, COUNT(*) as value 
            FROM marks 
            WHERE course_id = ? 
            GROUP BY grade
        `, [req.params.courseId]);
        res.json(rows);
    } catch (error) {
        res.status(500).json({ message: 'Error fetching grade distribution' });
    }
});

// Get departments list
router.get('/departments', async (req, res) => {
    try {
        const [rows] = await pool.execute('SELECT DISTINCT department FROM students UNION SELECT DISTINCT department FROM faculty');
        res.json(rows.map(r => r.department).filter(d => d));
    } catch (error) {
        res.status(500).json({ message: 'Error fetching departments' });
    }
});

module.exports = router;

const express = require('express');
const router = express.Router();
const pool = require('../db');
const authMiddleware = require('../middleware/authMiddleware');

// Protect all student routes
router.use(authMiddleware);

// Get student performance data with class average benchmarking
router.get('/:studentId/performance', async (req, res) => {
    try {
        const [marks] = await pool.execute(`
            SELECT 
                m.*, 
                c.course_name, 
                c.course_code,
                (SELECT AVG(total_marks) FROM marks WHERE course_id = m.course_id) as class_average
            FROM marks m 
            JOIN courses c ON m.course_id = c.id 
            WHERE m.student_id = ?
        `, [req.params.studentId]);
        res.json(marks);
    } catch (error) {
        res.status(500).json({ message: 'Error fetching student performance' });
    }
});

// Get student profile
router.get('/:userId/profile', async (req, res) => {
    try {
        const [rows] = await pool.execute('SELECT * FROM students WHERE user_id = ?', [req.params.userId]);
        if (rows.length === 0) return res.status(404).json({ message: 'Student not found' });
        res.json(rows[0]);
    } catch (error) {
        res.status(500).json({ message: 'Error fetching student profile' });
    }
});

// Get academic history (past semesters)
router.get('/:studentId/history', async (req, res) => {
    try {
        const [rows] = await pool.execute(`
            SELECT semester, academic_year, AVG(total_marks) as gpa 
            FROM marks 
            WHERE student_id = ? 
            GROUP BY semester, academic_year
            ORDER BY semester DESC
        `, [req.params.studentId]);
        res.json(rows);
    } catch (error) {
        res.status(500).json({ message: 'Error fetching academic history' });
    }
});

// Get attendance
router.get('/:studentId/attendance', async (req, res) => {
    try {
        const [rows] = await pool.execute(`
            SELECT a.date, a.status, c.course_name 
            FROM attendance a
            JOIN courses c ON a.course_id = c.id
            WHERE a.student_id = ?
            ORDER BY a.date DESC
        `, [req.params.studentId]);
        res.json(rows);
    } catch (error) {
        res.status(500).json({ message: 'Error fetching attendance' });
    }
});

// Get recent activities (system-wide or user specific - currently simplified to last 10 global)
router.get('/activities', async (req, res) => {
    try {
        const [rows] = await pool.execute(`
            SELECT description, timestamp as time 
            FROM activities 
            ORDER BY timestamp DESC 
            LIMIT 10
        `);
        res.json(rows);
    } catch (error) {
        res.status(500).json({ message: 'Error fetching activities' });
    }
});

module.exports = router;

